INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('english', 'WAEC', 'The hype with which he assumed of office', 'had met', 'might night', 'competent and efficient', 'energetic and sporty', NULL, 'C', '"Competent and efficient" best captures someone who is able and effective in performing their duties.', 2025), 
('english', 'WAEC', 'The doctor has earlier warned the patient', 'cautious', 'could not', 'cannot', 'should not', NULL, 'D', 'The correct modal in the context of a doctor''s warning is "should not" — indicating advice or instruction.', 2025), 
('english', 'WAEC', 'The company was granted a stay of execution. This means that the action against the company should be:', 'stopped', 'prioritized', 'suspended', 'discarded', NULL, 'C', '"Stay of execution" is a legal term meaning the postponement or suspension of a legal action or sentence.', 2025), 
('english', 'WAEC', 'The ugly incidents of the bridge are water under the bridge. This means that the incidents:', 'continue to haunt us', 'have been experienced again', 'have been forgotten', 'cannot be forgotten', NULL, 'C', '"Water under the bridge" is an idiom meaning something that happened in the past and is no longer worth worrying about — it has been forgotten.', 2025), 
('english', 'WAEC', 'My heart was in my mouth as I tried to open the envelope. This means that:', 'the man was very courageous', 'the man was very frightened', 'no one helped the man', 'the man acted very well', NULL, 'B', '"My heart was in my mouth" is an idiom meaning feeling very frightened or nervous about something.', 2025), 
('english', 'WAEC', 'Improvement in technology has expanded the frontiers of knowledge. "Frontiers" means:', 'borders', 'bounds', 'partitions', 'portions', NULL, 'B', '"Frontiers of knowledge" refers to the limits or boundaries of what is known — nearest in meaning to "bounds."', 2025), 
('english', 'WAEC', 'This type of music is inappropriate for the aged, it is:', 'unsuitable', 'unfit', 'objectionable', 'indecent', NULL, 'A', '"Inappropriate" means not suitable or proper for a particular person, purpose or situation — nearest in meaning to "unsuitable."', 2025), 
('english', 'WAEC', 'Such a solemn occasion is a music ceremony', 'unfashionable', 'unbefitting', 'indecorous', 'unsuitable', NULL, 'B', '"Solemn occasion" and "music ceremony" contrast — music is "unbefitting" (not appropriate) for a solemn occasion.', 2025), 
('english', 'WAEC', 'Tolu is the most clever of all the class. Choosing the correct form:', 'cleverer', 'cleverest', 'more clever', 'most clever', NULL, 'B', '"Cleverest" is the correct superlative form for comparing more than two people. "Most clever" is also acceptable but "cleverest" is more standard.', 2025), 
('english', 'WAEC', 'Some students are fond of frivolous things', 'putting on', 'putting away', 'putting off', 'putting out', NULL, 'A', '"Fond of putting on" means to wear or display — "putting on" is the correct phrasal verb to collocate with "fond of frivolous things."', 2025), 
('english', 'WAEC', 'You should not say things that will put others in their stead.', 'not', 'above', 'below', 'behind', NULL, 'D', '"Put behind" means to make someone feel less important or lower than others — the correct preposition is "behind."', 2025), 
('english', 'WAEC', 'Some students are not privy to the school''s administrative decisions. "Privy to" means:', 'aware of', 'concerned about', 'opposed to', 'excluded from', NULL, 'A', '"Privy to" means having private knowledge of something — nearest in meaning to "aware of."', 2025), 
('english', 'WAEC', 'Mountains can be formed by volcanic eruptions. The word "Mountains" in the context:', 'emissions', 'eruptions', 'filtering', 'puttering', NULL, 'B', 'Volcanic "eruptions" are what form mountains — this is the correct geological term.', 2025), 
('english', 'WAEC', 'The headmaster advised his pupils to exhibit some amount of decorum. "Decorum" means:', 'foolishness', 'gentility', 'intellect', 'dangerous', NULL, 'B', '"Decorum" means behaviour in keeping with good taste and propriety — nearest in meaning to "gentility."', 2025), 
('english', 'WAEC', 'Ann''s behaviour has been considered very weird. "Weird" means:', 'wicked', 'strange', 'lousy', 'ridiculous', NULL, 'B', '"Weird" means strange or unusual — nearest in meaning to "strange."', 2025), 
('english', 'WAEC', 'It is not uncommon for students to to correct their teachers and classmates.', 'unusual', 'natural', 'funny', 'inappropriate', NULL, 'A', '"Not uncommon" means "usual" or "expected." The opposite of uncommon is "usual," making "unusual" the nearest antonym.', 2025), 
('english', 'WAEC', 'Most of his suggestion were absurd', 'evocative', 'expressive', 'misdirected', 'misunderstood', NULL, 'C', '"Absurd" suggestions are those that are illogical or misguided — nearest in meaning to "misdirected."', 2025), 
('english', 'WAEC', 'The electorate misunderstood the information during the elections.', 'misapprehended', 'misconstrued', 'misplaced', 'misinformed', NULL, 'B', '"Misconstrued" means to interpret something incorrectly — nearest in meaning to "misunderstood."', 2025), 
('english', 'WAEC', 'The venture has a slim chance of success, it is:', 'has very long shot', 'long shot of success', 'a long shot', 'long shot', NULL, 'C', '"A long shot" is a venture with a slim chance of success — the correct idiomatic expression.', 2025), 
('english', 'WAEC', 'The situation was difficult because he:', 'had confessed earlier on and he was trusted', 'he was trusted', 'hadn''t confessed on', 'face challenges', NULL, 'A', 'The sentence requires past perfect "had confessed" and the conjunction "and" to link the two clauses correctly.', 2025), 
('english', 'WAEC', 'As a school prefect, I need to ban the use of plastic bags in our community. Write a letter to the chairperson of your municipal council.', 'notify', 'inform', 'intend to', 'request', NULL, 'B', 'The appropriate formal register for addressing a chairperson about banning plastic bags is to "inform" them of your position — the most formal and appropriate option.', 2025), 
('english', 'WAEC', 'Solitude is not good for the aged, it makes them lonely. "Solitude" means:', 'independence', 'isolation', 'privacy', 'seclusion', NULL, 'B', '"Solitude" means the state of being alone, often by choice — nearest in meaning to "isolation."', 2025), 
('english', 'WAEC', 'Your municipal council intends to ban the use of plastic bags in the community. "Insoluble" means:', 'impossible', 'unsolvable', 'unresolvable', 'unsuitable', NULL, 'B', '"Insoluble" when used in a figurative sense means not able to be solved or resolved — nearest in meaning to "unsolvable."', 2025), 
('english', 'WAEC', 'The situation appeared:', 'direct', 'tactful', 'ominous', 'reasonable', NULL, 'C', '"Ominous" gives the impression that something bad is going to happen — the most appropriate word in the context of an threatening situation.', 2025), 
('english', 'WAEC', 'The complete loss or absence of hope is called:', 'Distrust', 'Distress', 'Disgust', 'Despair', NULL, 'D', '"Despair" means the complete loss or absence of hope — the correct answer for the passage context about loss of hope.', 2025), 
('english', 'WAEC', 'To make a bad situation worse is to:', 'improve', 'exacerbate', 'attract', 'justify', NULL, 'B', '"Exacerbate" means to make a bad situation worse — the correct word in the context of worsening a problem.', 2025), 
('english', 'WAEC', 'The opposite of despair is:', 'hope', 'despair', 'despondent', 'fear', NULL, 'A', '"Hope" is the direct conceptual opposite of "despair" — the antonym required in the passage.', 2025), 
('english', 'WAEC', 'The truth was that he:', 'Had confessed earlier on, but he wasn''t trusted', 'not about dealing promptly', 'correct', 'wasn''t trusted', NULL, 'A', 'The correct interpretation of the passage requires "had confessed earlier on, but he wasn''t trusted" — past perfect with a contrastive conjunction.', 2025), 
('english', 'WAEC', 'To have a selfish aim or ulterior motive is:', 'a selfish motive', 'about acting promptly', 'to have an axe to grind', 'an ulterior motive', NULL, 'C', '"To have an axe to grind" is an idiom meaning to have a selfish aim or ulterior motive — the correct idiomatic expression.', 2025), 
('english', 'WAEC', 'Not being aware of or concerned about what is happening around one is:', 'oblivious', 'ignorant', 'wicked', 'deceitful', NULL, 'A', '"Oblivious" means not aware of or concerned about what is happening around one — the most appropriate word in this context.', 2025), 
('english', 'WAEC', 'Acting in a brave, heroic and courageous manner is acting:', 'gallantly', 'practically', 'heretically', 'by instinct', NULL, 'A', '"Gallantly" means brave, heroic and courageous, acting in a chivalrous manner — the most appropriate adverb in this context.', 2025), 
('english', 'WAEC', 'A medical reaction to a substance is an:', 'illnesses', 'allergy', 'Frittering', 'addiction', NULL, 'B', '"Allergy" is a medical reaction to a substance — the correct term for the given context involving medical conditions.', 2025), 
('english', 'WAEC', 'Someone who is stubbornly uncooperative is:', 'relief', 'herd', 'recalcitrant', 'reluctant', NULL, 'C', '"Recalcitrant" means stubbornly uncooperative — the most appropriate word describing someone who refuses to submit to authority.', 2025), 
('english', 'WAEC', 'The state of being private and away from other people is:', 'independence', 'isolation', 'seclusion', 'privacy', NULL, 'C', '"Seclusion" means the state of being private and away from other people — the correct word in the context of isolation.', 2025), 
('english', 'WAEC', 'Very early in the morning is:', 'is in a position to make a difficult decision', 'crack of dawn', 'very early in the morning', 'misunderstanding', NULL, 'C', '"Crack of dawn" means very early in the morning — the correct idiomatic interpretation.', 2025), 
('english', 'WAEC', 'Ekpong was sure of some food.', 'implies confidence in availability', 'implies uncertainty', 'implies a basic assumption', 'implies a desire', NULL, 'A', '"Sure of" implies confidence that something is available or will happen — the correct interpretation.', 2025), 
('english', 'WAEC', 'Someone who is fully capable and qualified is:', 'complete and competent', 'honest', 'attractive', 'eloquent', NULL, 'A', '"Complete and competent" best describes someone who is fully capable and qualified — the correct interpretation.', 2025), 
('english', 'WAEC', 'Officially declared to be unfit or worthy of punishment is:', 'rags', 'privacy', 'murky', 'condemned', NULL, 'D', '"Condemned" means officially declared to be unfit or worthy of punishment — the correct word in this context.', 2025), 
('english', 'WAEC', 'Through all circumstances, good and bad is:', 'wicked', 'thick and thin', 'nothing', 'beside', NULL, 'B', '"Thick and thin" is the correct phrase meaning through all circumstances, good and bad — the correct idiomatic expression.', 2025), 
('english', 'WAEC', 'Ekpong''s share of the food was not enough.', 'would not satisfy him', 'would satisfy him', 'is insufficient quantity', 'is too little', NULL, 'C', '"Insufficient quantity" correctly describes Ekpong''s share of food that was not enough — the correct interpretation.', 2025), 
('english', 'WAEC', 'Easy to understand or perceive is:', 'clear', 'wicked', 'much', 'unimportant', NULL, 'A', '"Clear" means easy to understand or perceive — the correct word in this context.', 2025), 
('english', 'WAEC', 'A period of time from now:', 'two weeks', 'in two weeks', 'since two weeks', 'during two weeks', NULL, 'B', '"In two weeks" is the correct preposition phrase indicating a period of time from now — the correct temporal expression.', 2025), 
('english', 'WAEC', 'Passengers are allowed to carry _________ luggage.', 'many', 'large', 'a few', 'much', NULL, 'D', '"Much luggage" is correct because "luggage" is an uncountable noun and takes "much" not "many" or "a few."', 2025), 
('english', 'WAEC', 'If she had prepared well for the examination, she _________.', 'would have won the scholarship', 'will win the scholarship', 'would win the scholarship', 'could win the scholarship', NULL, 'A', 'The conditional type 3 requires "would have + past participle" to indicate an action that did not happen in the past.', 2025), 
('english', 'WAEC', 'Peter and Paul come often _________', 'to visit', 'visiting', 'for a visit', 'for visiting', NULL, 'A', '"Come often to visit" is the correct infinitive construction following the verb "come" to indicate purpose.', 2025), 
('english', 'WAEC', 'We put the phone down for our _________.', 'fathers-in-law', 'father-in-laws', 'father-in-law', 'fathers-in-laws', NULL, 'A', '"Fathers-in-law" is the correct plural of "father-in-law" — the noun "father" takes the plural -s, not the preposition or "law."', 2025), 
('english', 'WAEC', 'The class visited the apiary _________.', 'in two weeks', 'besides', 'football', 'basketball', NULL, 'A', '"In two weeks" is the correct time expression — indicating the visit happened within a two-week period.', 2025), 
('english', 'WAEC', 'Tolu wanted the football team to concede _________.', 'receipt', 'import', 'oblique', 'deceive', NULL, 'A', '"Concede" in football means to allow the opposing team to score. "Receipt" is unrelated — the question tests vocabulary in football register context.', 2025), 
('english', 'WAEC', 'Eventually it took the _________ to resolve the issue.', 'purchase', 'regulation', 'pulled', 'intervention', NULL, 'D', '"Intervention" means the act of becoming involved in a situation to change what is happening — the correct word in this context.', 2025);
